import{G as a,c as o,b as r,ae as e}from"./chunks/framework.Cpb2nuHT.js";const s="/assets/file-20260414205543.DZMgzQ1T.jpg",l="/assets/file-20260414212000.gZvI95Uz.jpg",h=JSON.parse('{"title":"垃圾自动回收","description":"","frontmatter":{"title":"垃圾自动回收","date":"2026/4/14 20:43","author":"花木凋零成兰","tags":["Java","JVM"],"hiddenCover":true},"headers":[],"relativePath":"Java/JVM/06_垃圾自动回收.md","filePath":"Java/JVM/06_垃圾自动回收.md","lastUpdated":1776173858000}'),n={name:"Java/JVM/06_垃圾自动回收.md"};function i(g,t,p,_,d,c){return r(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776199380000"},[...t[0]||(t[0]=[e('<h1 id="垃圾自动回收" tabindex="-1">垃圾自动回收 <a class="header-anchor" href="#垃圾自动回收" aria-label="Permalink to &quot;垃圾自动回收&quot;">​</a></h1><blockquote><p>在 C/C++ 这种没有自动垃圾回收机制的语言中，一个对象如果不再使用，则需要手动进行释放，否则会出现内存泄露；</p><p>这种释放对象的过程叫做垃圾回收，需要编写代码进行回收的方式被称为<strong>手动回收</strong>；</p><p><strong>内存泄漏</strong>：指的是不再使用的对象在系统中未被回收；内存泄漏的积累可能会导致内存溢出；</p></blockquote><p>Java 中为了简化对象的释放，引入了自动<strong>垃圾回收（Garbage Collection 简称 GC）机制</strong>；通过垃圾回收器对不再使用的对象完成自动的回收，<strong>垃圾回收器主要负责对堆上的内存进行回收</strong>；如 C#、Python、Go 都拥有自己的垃圾回收器；</p><p><img src="'+s+'" alt="" loading="lazy"></p><p><strong>自动与手动垃圾回收对比</strong>：</p><ul><li>自动垃圾回收：自动根据对象是否使用由虚拟机来回收对象； <ul><li>优点：<strong>降低程序员实现难度</strong> ，降低对象回收 bug 出现的可能性；</li><li>缺点：程序员<strong>无法控制垃圾回收的及时性</strong>；</li></ul></li><li>手动垃圾回收：由程序员编程实现对象的删除； <ul><li>优点：<strong>回收及时性高</strong>，由程序员把控回收的时机；</li><li>缺点：编写不当容易出现<strong>悬空指针</strong>、<strong>重复释放</strong>、<strong>内存泄漏</strong>等问题；</li></ul></li></ul><p>再次回顾<strong>运行时数据区</strong>，基本结构如下：</p><p><img src="'+l+'" alt="" loading="lazy"></p><p><a href="./05_运行时数据区.html">运行时数据区</a>中线程不共享的部分，是<strong>伴随着线程的创建而创建，线程的销毁而销毁</strong>；而方法的栈帧在执行完方法之后就<em>会自动弹出栈并释放掉对应的内存</em>；</p><h2 id="方法区回收" tabindex="-1">方法区回收 <a class="header-anchor" href="#方法区回收" aria-label="Permalink to &quot;方法区回收&quot;">​</a></h2><blockquote><p>方法区中能回收的内容主要是不再使用的类</p></blockquote><p>判断一个类可以被卸载，需要同时满足以下 3 个条件：</p><ol><li>此<strong>类所有实例对象都已经被回收</strong>，在<strong>堆中不存在任何该类的实例对象以及子类实例对象</strong>；</li><li>加载该类的类加载器已经被回收；</li><li>该类对应的 <code>java.lang.Class</code> 对象没有被任何地方引用；</li></ol><h2 id="堆回收" tabindex="-1">堆回收 <a class="header-anchor" href="#堆回收" aria-label="Permalink to &quot;堆回收&quot;">​</a></h2>',14)])])}const m=a(n,[["render",i]]);export{h as __pageData,m as default};
